/* tors_geo.js — Torsione low-poly decimata  |  SCALE=22
   1274 vertici, 2059 triangoli
   Normalizzazione: centra bbox, scala Y → [-2.2, 2.2] */
(function(){
  var vb64="";
  var fb64="";
  function dec(s,T){var b=atob(s),a=new Uint8Array(b.length);for(var i=0;i<b.length;i++)a[i]=b.charCodeAt(i);return new T(a.buffer);}
  window.TORS_V=dec(vb64,Float32Array);
  window.TORS_F=dec(fb64,Int32Array);
})();
